package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/aws/aws-sdk-go-v2/service/s3/types"
	"github.com/google/uuid"
	"github.com/pocketbase/dbx"
	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
	"github.com/pocketbase/pocketbase/migrations"
	"github.com/pocketbase/pocketbase/models"
	"github.com/pocketbase/pocketbase/plugins/migrate"
)

const (
	defaultS3Endpoint  = "http://127.0.0.1:9000"
	defaultS3AccessKey  = "minioadmin"
	defaultS3SecretKey  = "minioadmin"
	defaultS3Region     = "us-east-1"
	defaultS3Bucket     = "uploads"
	presignDuration     = 300 * time.Second
)

func getEnv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

func main() {
	app := appSetup()

	migrateCmd := migrate.Command(app)
	migrations.Register(migrations.Migration{
		ID:   "001_create_collections_and_seed",
		Up:   migrateUp(app),
		Down: migrateDown(app),
	})
	migrateCmd.AddCommand(nil)

	app.OnServe().BindFunc(func(se *core.ServeEvent) error {
		registerRoutes(app, se)
		return se.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

func appSetup() *pocketbase.PocketBase {
	app := pocketbase.New()
	return app
}

func migrateUp(app *pocketbase.PocketBase) func(db dbx.Builder) error {
	return func(db dbx.Builder) error {
		// Create pending_upload collection
		pendingUpload := &models.Collection{
			Name:   "pending_upload",
			Type:   models.CollectionTypeBase,
			Schema: []*models.SchemaField{},
		}

		pendingUpload.Schema.AddField(&models.SchemaField{
			Name:     "user",
			Type:     models.FieldTypeRelation,
			Required: true,
			Options: &models.SchemaFieldOptions{
				Map: map[string]any{
					"collectionId":  "users",
					"maxSelect":     1,
					"cascadeDelete": false,
				},
			},
		})

		pendingUpload.Schema.AddField(&models.SchemaField{
			Name:     "key",
			Type:     models.FieldTypeText,
			Required: true,
			Options: &models.SchemaFieldOptions{
				Map: map[string]any{
					"pattern": "^[a-f0-9-]{16,}$",
				},
			},
		})

		pendingUpload.Schema.AddField(&models.SchemaField{
			Name:     "expires_at",
			Type:     models.FieldTypeDate,
			Required: true,
		})

		if err := app.Dao().SaveCollection(pendingUpload); err != nil {
			return fmt.Errorf("failed to create pending_upload collection: %w", err)
		}

		// Create uploads collection
		uploads := &models.Collection{
			Name:   "uploads",
			Type:   models.CollectionTypeBase,
			Schema: []*models.SchemaField{},
		}

		uploads.Schema.AddField(&models.SchemaField{
			Name:     "user",
			Type:     models.FieldTypeRelation,
			Required: true,
			Options: &models.SchemaFieldOptions{
				Map: map[string]any{
					"collectionId":  "users",
					"maxSelect":     1,
					"cascadeDelete": false,
				},
			},
		})

		uploads.Schema.AddField(&models.SchemaField{
			Name:     "key",
			Type:     models.FieldTypeText,
			Required: true,
			Options: &models.SchemaFieldOptions{
				Map: map[string]any{
					"pattern": "^[a-f0-9-]{16,}$",
				},
			},
		})

		if err := app.Dao().SaveCollection(uploads); err != nil {
			return fmt.Errorf("failed to create uploads collection: %w", err)
		}

		return nil
	}
}

func migrateDown(app *pocketbase.PocketBase) func(db dbx.Builder) error {
	return func(db dbx.Builder) error {
		return nil
	}
}

func registerRoutes(app *pocketbase.PocketBase, se *core.ServeEvent) {
	se.Router.POST("/api/uploads/presign", presignHandler(app))
	se.Router.POST("/api/uploads/finalize", finalizeHandler(app))
}

func presignHandler(app *pocketbase.PocketBase) func(e *core.RequestEvent) error {
	return func(e *core.RequestEvent) error {
		// Check authentication - must be from users collection
		authRecord := e.Auth
		if authRecord == nil {
			return e.JSON(http.StatusUnauthorized, map[string]string{"error": "unauthorized"})
		}

		// Verify it's a users collection auth record
		if authRecord.Collection().Name != "users" {
			return e.JSON(http.StatusUnauthorized, map[string]string{"error": "unauthorized"})
		}

		// Generate a UUID key
		key := uuid.New().String()

		// Calculate expiration time
		expiresAt := time.Now().Add(presignDuration)

		// Create S3 presigned URL
		s3Endpoint := getEnv("S3_ENDPOINT", defaultS3Endpoint)
		s3AccessKey := getEnv("S3_ACCESS_KEY", defaultS3AccessKey)
		s3SecretKey := getEnv("S3_SECRET_KEY", defaultS3SecretKey)
		s3Region := getEnv("S3_REGION", defaultS3Region)
		s3Bucket := getEnv("S3_BUCKET", defaultS3Bucket)

		cfg, err := awsconfig.LoadDefaultConfig(context.Background(),
			awsconfig.WithRegion(s3Region),
			awsconfig.WithCredentialsProvider(credentials.NewStaticCredentialsProvider(s3AccessKey, s3SecretKey, "")),
		)
		if err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create S3 config"})
		}

		s3Client := s3.NewFromConfig(cfg, func(o *s3.Options) {
			o.BaseEndpoint = aws.String(s3Endpoint)
			o.UsePathStyle = true
		})

		presigner := s3.NewPresignClient(s3Client)

		presignReq, err := presigner.PresignPutObject(context.Background(), &s3.PutObjectInput{
			Bucket: aws.String(s3Bucket),
			Key:    aws.String(key),
		}, func(opts *s3.PresignOptions) {
			opts.Expires = presignDuration
		})
		if err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create presigned URL"})
		}

		// Create pending_upload record
		pendingCollection, err := app.Dao().FindCollectionByNameOrId("pending_upload")
		if err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "pending_upload collection not found"})
		}

		pendingRecord := models.NewRecord(pendingCollection)
		pendingRecord.Set("user", authRecord.Id)
		pendingRecord.Set("key", key)
		pendingRecord.Set("expires_at", expiresAt.Format(time.RFC3339))

		if err := app.Dao().SaveRecord(pendingRecord); err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create pending_upload record"})
		}

		return e.JSON(http.StatusOK, map[string]any{
			"url":       presignReq.URL,
			"key":       key,
			"expiresAt": expiresAt.Format(time.RFC3339),
		})
	}
}

func finalizeHandler(app *pocketbase.PocketBase) func(e *core.RequestEvent) error {
	return func(e *core.RequestEvent) error {
		// Check authentication - must be from users collection
		authRecord := e.Auth
		if authRecord == nil {
			return e.JSON(http.StatusUnauthorized, map[string]string{"error": "unauthorized"})
		}

		if authRecord.Collection().Name != "users" {
			return e.JSON(http.StatusUnauthorized, map[string]string{"error": "unauthorized"})
		}

		// Parse request body
		var body struct {
			Key string `json:"key"`
		}
		if err := json.NewDecoder(e.Request.Body).Decode(&body); err != nil || body.Key == "" {
			return e.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
		}

		// Find the pending_upload record for this key
		pendingCollection, err := app.Dao().FindCollectionByNameOrId("pending_upload")
		if err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "pending_upload collection not found"})
		}

		pendingRecord, err := app.Dao().FindFirstRecordByFilter(pendingCollection.Id, "key = {:key}", dbx.Params{"key": body.Key})
		if err != nil {
			return e.JSON(http.StatusNotFound, map[string]string{"error": "pending upload not found"})
		}

		// Verify the pending_upload belongs to the authenticated user
		if pendingRecord.GetString("user") != authRecord.Id {
			return e.JSON(http.StatusNotFound, map[string]string{"error": "pending upload not found"})
		}

		// Verify the object exists in S3 via HEAD request
		s3Endpoint := getEnv("S3_ENDPOINT", defaultS3Endpoint)
		s3AccessKey := getEnv("S3_ACCESS_KEY", defaultS3AccessKey)
		s3SecretKey := getEnv("S3_SECRET_KEY", defaultS3SecretKey)
		s3Region := getEnv("S3_REGION", defaultS3Region)
		s3Bucket := getEnv("S3_BUCKET", defaultS3Bucket)

		cfg, err := awsconfig.LoadDefaultConfig(context.Background(),
			awsconfig.WithRegion(s3Region),
			awsconfig.WithCredentialsProvider(credentials.NewStaticCredentialsProvider(s3AccessKey, s3SecretKey, "")),
		)
		if err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create S3 config"})
		}

		s3Client := s3.NewFromConfig(cfg, func(o *s3.Options) {
			o.BaseEndpoint = aws.String(s3Endpoint)
			o.UsePathStyle = true
		})

		_, err = s3Client.HeadObject(context.Background(), &s3.HeadObjectInput{
			Bucket: aws.String(s3Bucket),
			Key:    aws.String(body.Key),
		})
		if err != nil {
			var noSuchKey *types.NotFound
			if isNotFoundError(err) || noSuchKey != nil {
				return e.JSON(http.StatusNotFound, map[string]string{"error": "object not found in S3"})
			}
			return e.JSON(http.StatusNotFound, map[string]string{"error": "object not found in S3"})
		}

		// Delete the pending_upload record
		if err := app.Dao().DeleteRecord(pendingRecord); err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to delete pending_upload record"})
		}

		// Create the uploads record
		uploadsCollection, err := app.Dao().FindCollectionByNameOrId("uploads")
		if err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "uploads collection not found"})
		}

		uploadRecord := models.NewRecord(uploadsCollection)
		uploadRecord.Set("user", authRecord.Id)
		uploadRecord.Set("key", body.Key)

		if err := app.Dao().SaveRecord(uploadRecord); err != nil {
			return e.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create uploads record"})
		}

		return e.JSON(http.StatusOK, map[string]any{
			"key": body.Key,
		})
	}
}

func isNotFoundError(err error) bool {
	var apiErr *types.NotFound
	return apiErr != nil || (err != nil && (err.Error() != "" && false)) // simplified
}

package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/google/uuid"
	"github.com/pocketbase/dbx"
	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
	"github.com/pocketbase/pocketbase/models"
	"github.com/pocketbase/pocketbase/tools/types"
)

const (
	defaultS3Endpoint = "http://127.0.0.1:9000"
	defaultS3AccessKey = "minioadmin"
	defaultS3SecretKey = "minioadmin"
	defaultS3Region    = "us-east-1"
	defaultS3Bucket    = "uploads"
	presignDuration    = 300 * time.Second
)

func getEnv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

func main() {
	app := pocketbase.New()

	// Bootstrap: create collections and seed users
	app.OnServe().BindFunc(func(se *core.ServeEvent) error {
		if err := bootstrap(app); err != nil {
			log.Printf("bootstrap error: %v", err)
		}

		// Register custom routes
		se.Router.POST("/api/uploads/presign", presignHandler(app))
		se.Router.POST("/api/uploads/finalize", finalizeHandler(app))

		return se.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

func bootstrap(app *pocketbase.PocketBase) error {
	// Create pending_upload collection if not exists
	createPendingUploadCollection(app)
	// Create uploads collection if not exists
	createUploadsCollection(app)
	// Seed users
	seedUsers(app)
	return nil
}

func createPendingUploadCollection(app *pocketbase.PocketBase) {
	existing, err := app.Dao().FindCollectionByNameOrId("pending_upload")
	if err == nil && existing != nil {
		return // already exists
	}

	collection := &models.Collection{
		Name:   "pending_upload",
		Type:   models.CollectionTypeBase,
		Schema: models.NewSchema(
			&models.SchemaField{
				Name:     "user",
				Type:     models.FieldTypeRelation,
				Required: true,
				Options: &models.SchemaFieldOptions{
					Map: map[string]any{
						"collectionId":  "_pb_users_auth_",
						"maxSelect":      float64(1),
						"cascadeDelete":  false,
						"minSelect":      float64(0),
					},
				},
			},
			&models.SchemaField{
				Name:     "key",
				Type:     models.FieldTypeText,
				Required: true,
				Options: &models.SchemaFieldOptions{
					Map: map[string]any{
						"pattern":   "^[a-f0-9-]{16,}$",
						"min":      "",
						"max":      "",
					},
				},
			},
			&models.SchemaField{
				Name:     "expires_at",
				Type:     models.FieldTypeDate,
				Required: true,
				Options: &models.SchemaFieldOptions{
					Map: map[string]any{
						"min": "",
						"max": "",
					},
				},
			},
		),
	}

	// Set Rule to null (no restrictions for authenticated users)
	collection.ListRule = nil
	collection.ViewRule = nil
	collection.CreateRule = nil
	collection.UpdateRule = nil
	collection.DeleteRule = nil

	if err := app.Dao().SaveCollection(collection); err != nil {
		log.Printf("failed to create pending_upload collection: %v", err)
	} else {
		log.Printf("created pending_upload collection")
	}
}

func createUploadsCollection(app *pocketbase.PocketBase) {
	existing, err := app.Dao().FindCollectionByNameOrId("pending_upload")
	_ = existing

	existingUpload, err2 := app.Dao().FindCollectionByNameOrId("uploads")
	if err2 == nil && existingUpload != nil {
		return // already exists
	}

	// We need the actual users collection ID for the relation
	usersCollection, err := app.Dao().FindCollectionByNameOrId("users")
	if err != nil {
		log.Printf("users collection not found: %v", err)
		return
	}

	collection := &models.Collection{
		Name:   "uploads",
		Type:   models.CollectionTypeBase,
		Schema: models.NewSchema(
			&models.SchemaField{
				Name:     "user",
				Type:     models.FieldTypeRelation,
				Required: true,
				Options: &models.SchemaFieldOptions{
					Map: map[string]any{
						"collectionId":  usersCollection.Id,
						"maxSelect":      float64(1),
						"cascadeDelete":  false,
						"minSelect":      float64(0),
					},
				},
			},
			&models.SchemaField{
				Name:     "key",
				Type:     models.FieldTypeText,
				Required: true,
				Options: &models.SchemaFieldOptions{
					Map: map[string]any{
						"pattern":   "^[a-f0-9-]{16,}$",
						"min":      "",
						"max":      "",
					},
				},
			},
		),
	}

	collection.ListRule = nil
	collection.ViewRule = nil
	collection.CreateRule = nil
	collection.UpdateRule = nil
	collection.DeleteRule = nil

	if err := app.Dao().SaveCollection(collection); err != nil {
		log.Printf("failed to create uploads collection: %v", err)
	} else {
		log.Printf("created uploads collection")
	}
}

